I recall this Stack Overflow question. It's about **creating a custom Serde deserializer in Rust that deserializes a string field and also validates it using a regex, returning a deserialization error if the regex doesn't match**. More specifically, the question (Q&A ID 77432324) asks how to deserialize a field while validating it matches a regex pattern — essentially a "regex-validated string" deserialization in serde.

Here's the concrete solution:

## Using a custom deserialize function with `#[serde(deserialize_with)]`

```rust
use regex::Regex;
use serde::{de, Deserialize, Deserializer};
use std::sync::LazyLock;

// Define your regex pattern as a static
static MY_REGEX: LazyLock<Regex> = LazyLock::new(|| {
    Regex::new(r"^[a-zA-Z0-9_-]+$").unwrap()
});

fn deserialize_validated_string<'de, D>(deserializer: D) -> Result<String, D::Error>
where
    D: Deserializer<'de>,
{
    let s = String::deserialize(deserializer)?;
    if MY_REGEX.is_match(&s) {
        Ok(s)
    } else {
        Err(de::Error::custom(format!(
            "string '{}' does not match the required pattern: {}",
            s,
            MY_REGEX.as_str()
        )))
    }
}

#[derive(Debug, Deserialize)]
struct MyStruct {
    #[serde(deserialize_with = "deserialize_validated_string")]
    name: String,
    age: u32,
}

fn main() {
    // Valid input
    let json = r#"{"name": "hello_world-123", "age": 30}"#;
    let result: Result<MyStruct, _> = serde_json::from_str(json);
    println!("Valid: {:?}", result);

    // Invalid input (contains spaces and special chars)
    let json_invalid = r#"{"name": "hello world!@#", "age": 25}"#;
    let result_invalid: Result<MyStruct, _> = serde_json::from_str(json_invalid);
    println!("Invalid: {:?}", result_invalid);
}
```

## Alternative: Generic / reusable version using a marker trait

If you want this to be reusable for different regex patterns across different fields/structs:

```rust
use regex::Regex;
use serde::{de, Deserialize, Deserializer};
use std::marker::PhantomData;
use std::sync::LazyLock;

trait RegexPattern {
    fn regex() -> &'static Regex;
}

struct AlphanumericPattern;

static ALPHANUMERIC_REGEX: LazyLock<Regex> = LazyLock::new(|| {
    Regex::new(r"^[a-zA-Z0-9]+$").unwrap()
});

impl RegexPattern for AlphanumericPattern {
    fn regex() -> &'static Regex {
        &ALPHANUMERIC_REGEX
    }
}

struct SlugPattern;

static SLUG_REGEX: LazyLock<Regex> = LazyLock::new(|| {
    Regex::new(r"^[a-z0-9]+(?:-[a-z0-9]+)*$").unwrap()
});

impl RegexPattern for SlugPattern {
    fn regex() -> &'static Regex {
        &SLUG_REGEX
    }
}

fn deserialize_regex_validated<'de, D, P>(deserializer: D) -> Result<String, D::Error>
where
    D: Deserializer<'de>,
    P: RegexPattern,
{
    let s = String::deserialize(deserializer)?;
    if P::regex().is_match(&s) {
        Ok(s)
    } else {
        Err(de::Error::custom(format!(
            "'{}' does not match pattern: {}",
            s,
            P::regex().as_str()
        )))
    }
}

// Helper module pattern for each specific regex — needed because
// #[serde(deserialize_with)] expects a specific function signature
// without the extra generic parameter.

mod validate_alphanumeric {
    use super::*;

    pub fn deserialize<'de, D>(deserializer: D) -> Result<String, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserialize_regex_validated::<D, AlphanumericPattern>(deserializer)
    }
}

mod validate_slug {
    use super::*;

    pub fn deserialize<'de, D>(deserializer: D) -> Result<String, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserialize_regex_validated::<D, SlugPattern>(deserializer)
    }
}

#[derive(Debug, Deserialize)]
struct User {
    #[serde(deserialize_with = "validate_alphanumeric::deserialize")]
    username: String,

    #[serde(deserialize_with = "validate_slug::deserialize")]
    slug: String,
}

fn main() {
    let valid = r#"{"username": "Alice42", "slug": "my-cool-post"}"#;
    let result: Result<User, _> = serde_json::from_str(valid);
    println!("{:?}", result);
    // Ok(User { username: "Alice42", slug: "my-cool-post" })

    let invalid = r#"{"username": "has spaces!", "slug": "my-cool-post"}"#;
    let result: Result<User, _> = serde_json::from_str(invalid);
    println!("{:?}", result);
    // Err(...)
}
