  console.log("window.ai.languageModel is not available in this browser.");
} else {
  // 2. Check capabilities
  const capabilities = await window.ai.languageModel.capabilities();
  console.log("Available:", capabilities.available);
  // capabilities.available can be: "readily", "after-download", or "no"

  if (capabilities.available === "no") {
    console.log("The language model is not available.");
  } else {
    // 3. Create a session
    const session = await window.ai.languageModel.create({
      // Optional system prompt
