        });
      },
    });

    // 4. Prompt (non-streaming) — returns a string
    const result = await session.prompt("Explain quantum computing in simple terms.");
    console.log("Response:", result);

    // 5. Prompt (streaming) — returns a ReadableStream
    const stream = session.promptStreaming("Write a short poem about the ocean.");
