    for await (const chunk of stream) {
      // `chunk` is the full response so far (cumulative)
      console.log("Streaming chunk:", chunk);
    }

    // 6. Check token usage
    console.log("Tokens used so far:", session.tokensSoFar);
    console.log("Max tokens:", session.maxTokens);
    console.log("Tokens left:", session.tokensLeft);

    // 7. Count tokens for a given input without prompting
    const tokenCount = await session.countPromptTokens("Hello, how are you?");
    console.log("Token count:", tokenCount);

    // 8. Clone a session (preserves conversation history)
    const clonedSession = await session.clone();

    // 9. Destroy a session when done
    session.destroy();
  }
}
