# FedCM Federated Sign-In

Below is a relying party (RP) implementation that uses `navigator.credentials.get()` with an `identity` option to sign a user in via an identity provider (IdP).

## Basic sign-in request

```javascript
async function signIn() {
  // Feature detection: check that the FedCM identity option is supported.
  if (!("IdentityCredential" in window)) {
    console.error("FedCM is not supported in this browser.");
    return;
  }

  try {
    const credential = await navigator.credentials.get({
      identity: {
        // "optional" mediation behaves like a silent/auto request when possible.
        // Other valid values for mediation: "required", "optional", "silent".
        providers: [
          {
            // URL of the IdP's well-known config file (the manifest endpoint).
            configURL: "https://idp.example/fedcm.json",
            // The OAuth-style client ID registered with the IdP for this RP.
            clientId: "rp-client-id-12345",
            // Optional: opaque value forwarded to the IdP's id_assertion_endpoint.
            nonce: "a1b2c3d4",
          },
        ],
      },
      // Optional top-level mediation requirement.
      mediation: "optional",
    });

    // On success the promise resolves with an IdentityCredential instance.
    // credential.type === "identity"
    console.log("Credential type:", credential.type);

    // The identity assertion token returned by the IdP's id_assertion_endpoint.
    const token = credential.token;

    // Send the token to your backend to verify and establish a session.
    await fetch("/api/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ token }),
    });
  } catch (err) {
    // err may be a DOMException (e.g. "NetworkError", "NotAllowedError",
    // "AbortError") or an IdentityCredentialError.
    if (err.name === "IdentityCredentialError") {
      // Available when the IdP returns an error response from the
      // id_assertion_endpoint.
      console.error("IdP error:", err.code, err.url);
    } else {
      console.error("Sign-in failed:", err.name, err.message);
    }
  }
}

document.getElementById("login-btn")?.addEventListener("click", signIn);
