<button popovertarget="myPopover">Toggle Popover</button>

<!-- The popover attribute makes this element a popover -->
<div id="myPopover" popover>
  <p>This is popover content.</p>
</div>
```

- `popover` (defaults to `popover="auto"`) — light-dismiss enabled (closes on Escape or outside click).
- `popover="manual"` — must be closed explicitly; not light-dismissed.

## Controlling popovertarget Action

```html
<button popovertarget="menu" popovertargetaction="show">Show</button>
<button popovertarget="menu" popovertargetaction="hide">Hide</button>
<button popovertarget="menu" popovertargetaction="toggle">Toggle</button>

<div id="menu" popover="auto">
  <p>Menu content</p>
</div>
```

`popovertargetaction` accepts `"show"`, `"hide"`, or `"toggle"` (default is `"toggle"`).

## JavaScript Control

```html
<button id="openBtn">Open via JS</button>
<button id="toggleBtn">Toggle via JS</button>

<div id="jsPopover" popover="manual">
  <p>Controlled by JavaScript.</p>
  <button id="closeBtn">Close</button>
</div>

<script>
  const popover = document.getElementById('jsPopover');

  document.getElementById('openBtn').addEventListener('click', () => {
    // showPopover() throws if it's already open
    if (!popover.matches(':popover-open')) {
      popover.showPopover();
    }
  });

  document.getElementById('toggleBtn').addEventListener('click', () => {
    // togglePopover() returns true if open after the call, false otherwise.
    // You may pass a boolean force argument: togglePopover(true) / togglePopover(false)
    const isOpen = popover.togglePopover();
    console.log('Popover is now', isOpen ? 'open' : 'closed');
  });

  document.getElementById('closeBtn').addEventListener('click', () => {
    popover.hidePopover();
  });

  // The 'toggle' and 'beforetoggle' events fire on the popover element.
  popover.addEventListener('beforetoggle', (event) => {
    // event is a ToggleEvent with oldState / newState ("open" or "closed")
    console.log('beforetoggle:', event.oldState, '->', event.newState);
  });

