  /* Anchored elements must be absolutely or fixed positioned */
  position: absolute;

  /* Associate this element with the established anchor */
  position-anchor: --my-button-anchor;

  /* Position the bottom of the tooltip at the top of the anchor */
  bottom: anchor(top);

  /* Position the horizontal center of the tooltip to align with the horizontal center of the anchor */
