            // The Relying Party's (RP) client ID registered with the IdP
            clientId: "your-relying-party-client-id-12345",
            // An optional cryptographic nonce to prevent replay attacks
            nonce: "a-secure-random-nonce-value",
          }
        ],
      },
    });

    if (credential) {
      // 3. Extract the token from the resulting IdentityCredential object
      const token = credential.token;

      console.log("Successfully retrieved identity credential token!");

